import{_ as e,c as t,o,a4 as r}from"./chunks/framework.ttppV29E.js";const n="/assets/mcp-list-page.DT1PGbPy.png",m=JSON.parse('{"title":"MCP Servers","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp-servers/index.md","filePath":"docs/mcp-servers/index.md","lastUpdated":1773428355000}'),a={name:"docs/mcp-servers/index.md"},s=r('<h1 id="mcp-servers" tabindex="-1">MCP Servers <a class="header-anchor" href="#mcp-servers" aria-label="Permalink to &quot;MCP Servers&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Preview Feature</p><p>This feature is in preview and is not available in production environments.</p></div><p>MCP (Model Context Protocol) servers allow you to expose AireGlu endpoints as tools and resources that AI agents can discover and invoke. This enables integration with AI clients such as Claude Desktop, Cursor, and other MCP-compatible applications.</p><p>An MCP server in AireGlu is a named configuration that maps one or more of your existing endpoints to the MCP protocol. Each server supports semantic versioning, allowing you to evolve your AI-facing interface independently of the underlying endpoints.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><ul><li><strong>MCP Server</strong> - A named configuration containing one or more versions, each exposing a set of endpoints to AI agents.</li><li><strong>Version</strong> - A semantic version (e.g. <code>1.0.0</code>) within a server. Each version defines its own set of exposed endpoints and can be activated or deactivated independently.</li><li><strong>Default Version</strong> - The version used when an MCP client connects without specifying a version in the URI. Can be set during creation or changed later via the server actions menu.</li><li><strong>Tool</strong> - An endpoint exposed as an invocable action. AI agents call tools to perform operations (e.g. submit data, trigger a workflow).</li><li><strong>Resource</strong> - An endpoint exposed as readable data. AI agents read resources to retrieve information (e.g. fetch a dataset, read configuration).</li><li><strong>Connection URI</strong> - The URL an MCP client uses to connect to your server.</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>MCP server management requires the following claims on your user account:</p><table><thead><tr><th>Action</th><th>Required Claim</th></tr></thead><tbody><tr><td>View server list</td><td><code>list:McpServerConfig</code></td></tr><tr><td>View server details</td><td><code>view:McpServerConfig</code></td></tr><tr><td>Create a server</td><td><code>create:McpServerConfig</code></td></tr><tr><td>Edit a server</td><td><code>edit:McpServerConfig</code></td></tr><tr><td>Delete a server</td><td><code>delete:McpServerConfig</code></td></tr></tbody></table><p>Contact your administrator if you do not have the required permissions.</p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>MCP Servers are found under <strong>AI Tools &gt; MCP Servers</strong> in the main navigation.</p><p><img src="'+n+'" alt="mcp"></p>',13),i=[s];function d(c,l,p,v,h,g){return o(),t("div",null,i)}const f=e(a,[["render",d]]);export{m as __pageData,f as default};
